import { BrowserRouter, Routes, Route } from 'react-router-dom';
import MainApp from './MainApp';
import { useEffect } from 'react';
import { NotificationProvider } from './components/chat/NotificationContext';

const App = () => {


  return (
    <NotificationProvider>
      <BrowserRouter>
        <Routes>
          {/* <Route path="/callback" element={<div>Connecting to Spotify...</div>} /> */}
          <Route path="/" element={<MainApp />} />
        </Routes>
      </BrowserRouter>
    </NotificationProvider>
  );
};

export default App;

import { auth, provider } from "../../config/firebase.js";
import { signInWithPopup, createUserWithEmailAndPassword, signInWithEmailAndPassword } from "firebase/auth";
import React, { useState, useEffect } from "react";
import Cookies from 'universal-cookie';
import { ArrowRightDoubleIcon, CircleArrowDown02Icon, GoogleIcon } from "hugeicons-react";
import '../../styles/auth/Auth.css'
import { useNotifications } from '../chat/NotificationContext';

const cookies = new Cookies();

export const Auth = (props) => {
    const { setIsAuth } = props;
    const { requestPermission } = useNotifications();

    // State for email and password
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [isSignUp, setIsSignUp] = useState(false); // State to toggle between sign up and sign in
    const [errorMessage] = useState("");

    const handleGoogleSignIn = async () => {
        try {
          const result = await signInWithPopup(auth, provider);
          cookies.set("auth-token", result.user.refreshToken);
          setIsAuth(true);
          
          // Request notification permission after successful sign-in
          await requestPermission();
        } catch (err) {
          console.error("Google Sign-In Error:", err);
          alert("Failed to sign in with Google. Please try again.");
        }
      };
    
    
    const handleEmailPasswordSignIn = async (e) => {
        e.preventDefault();
        try {
                // Sign in with email and password
                const result = await signInWithEmailAndPassword(auth, email, password);
                cookies.set("auth-token", result.user.refreshToken);
            setIsAuth(true);
        } catch (err) {
            console.error(err);
        }
    };

    const handleEmailPasswordSignUp = async (e) => {
        e.preventDefault(); // Prevent default form submission
        try {
            // Sign up with email and password
            const result = await createUserWithEmailAndPassword(auth, email, password);
            cookies.set("auth-token", result.user.refreshToken);
            setIsAuth(true); // Set authentication state to true
        } catch (err) {
            console.error("Sign Up Error:", err);
            let errorMessage = "Failed to create an account. Please try again.";
            if (err.code === 'auth/invalid-email') {
                errorMessage = "The email address is not valid.";
            } else if (err.code === 'auth/email-already-in-use') {
                errorMessage = "The email address is already in use.";
            } else if (err.code === 'auth/weak-password') {
                errorMessage = "The password is too weak.";
            }
            alert(errorMessage);
        }
    };

    const handleSignUpClick = () => {
        setIsSignUp(true);
        const container = document.getElementById('container');
        container.classList.add("right-panel-active");
    };

    const handleSignInClick = () => {
        setIsSignUp(false);
        const container = document.getElementById('container');
        container.classList.remove("right-panel-active");
    };

    useEffect(() => {
        const signUpButton = document.getElementById('signUp');
        const signInButton = document.getElementById('signIn');
        const container = document.getElementById('container');

        signUpButton.addEventListener('click', () => {
            container.classList.add("right-panel-active");
        });

        signInButton.addEventListener('click', () => {
            container.classList.remove("right-panel-active");
        });

        // Cleanup event listeners on component unmount
        return () => {
            signUpButton.removeEventListener('click', () => {
                container.classList.add("right-panel-active");
            });
            signInButton.removeEventListener('click', () => {
                container.classList.remove("right-panel-active");
            });
        };
    }, []);
    return (
        <div className="auth-wrapper">
        <div className="container" id="container">
            <div className={`form-container ${isSignUp ? "sign-up-container" : "sign-in-container"}`}>
                {isSignUp ? (
                    <form className="form-container-create" onSubmit={handleEmailPasswordSignUp}>
                        <h1>Create Account</h1>
                        <div className="social-container">
                        <span>or use your email for registration</span>
                          <ArrowRightDoubleIcon/>
                            <GoogleIcon size={44} onClick={handleEmailPasswordSignUp} />
                        </div>
                        
                        <input 
                            className="form-container-input-create" 
                            type="text" 
                            placeholder="Name" 
                            required 
                        />
                        <input
                            className="form-container-input-create"
                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                        <input
                            className="form-container-input-create"
                            type="password"
                            placeholder="Password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                        <button className="form-container-button" type="submit" onClick={handleEmailPasswordSignUp}>Sign Up</button>
                    </form>
                ) : (
                    <form className="form-container-signin" onSubmit={handleEmailPasswordSignIn}>
                        <h1 className="sign-in-title">Sign in</h1>
                        <div className="social-container">
                            <GoogleIcon size={44} className="social-icon" onClick={handleGoogleSignIn} />
                        </div>
                        <span>or use your account</span>
                        <input
                            className="form-container-input-signin"
                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                        <input
                        className="form-container-input-signin"
                            type="password"
                            placeholder="Password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                        <button className="form-container-button-signin" type="submit">Sign In</button>
                        <a href="#">Forgot your password?</a>
                        <p className="sign-in-error">{errorMessage
                            }</p>
                    </form>
                )}
            </div>

            <div className="overlay-container">
                <div className="overlay">
                    <div className="overlay-panel  overlay-right">
                        <h1>Welcome Back!</h1>
                        <p>To keep connected with us please login with your personal info</p>
                        <p>First Time User ?</p>
                        <CircleArrowDown02Icon className="overlay-icon" />
                        <button className="ghost" id="signUp" onClick={handleSignUpClick}>Sign Up</button>
                    </div>
                    <div className="overlay-panel overlay-left">
                        <h1>Hello, Friend!</h1>
                        <p>Enter your personal details and start your journey with us</p>
                        <p>Already a user?</p>
                        <CircleArrowDown02Icon className="overlay-icon" />
                        <button className="ghost" id="signIn" onClick={handleSignInClick}>Sign In</button>  
                    </div>
                </div>
            </div>
        </div>
        </div>
    );
};

import React, { useEffect, useState, useRef } from 'react';
import {
  addDoc,
  collection,
  onSnapshot,
  serverTimestamp,
  query,
  orderBy,
  doc,
  getDoc,
  updateDoc,
  arrayUnion,
  getDocs,
  writeBatch
} from 'firebase/firestore';
import { auth, db } from '../../config/firebase';
import { onAuthStateChanged } from 'firebase/auth';
import ChatRequestPopup from './ChatRequestPopup';
import '../../styles/chat/MessageArea.css';
import '../../styles/chat/Reactions.css';
import MessageInput from './MessageInput';
import MessageHeader from './MessageHeader';
import MessageContent from './MessageContent';

import PinnedMessagesOverlay from './PinnedMessagesOverlay';
import MentionsOverlay from './MentionsOverlay';



const Chat = ({ room, onError, showNotification }) => {
  const [roomData, setRoomData] = useState(null);
  const messageContentRef = useRef(null)
  const [newMessage, setNewMessage] = useState("");
  const [messages, setMessages] = useState([]);
  const [searchResults, setSearchResults] = useState(null);
  const [users] = useState([]);
  const [userEmail, setUserEmail] = useState(null);
  const [joinRequest, setJoinRequest] = useState(null);
  const [isRoomCreator, setIsRoomCreator] = useState(false);
  const [selectedReply, setSelectedReply] = useState(null);
  const [selectedMessageId, setSelectedMessageId] = useState(null);
  const reactions = ['­ƒöÑ', '­ƒÿé', '­ƒñ¼', '­ƒÿè', '­ƒ½á', '­ƒÿ¡'];
  const [isRecording, setIsRecording] = useState(false);
  const [recordingDuration, setRecordingDuration] = useState(0);
  const [previewAudio, setPreviewAudio] = useState(null);
  const [showPreview, setShowPreview] = useState(false);
  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const timerRef = useRef(null);
  const inputRef = useRef(null);
  const [isPinnedOpen, setIsPinnedOpen] = useState(false);
  const [isMentionsOpen, setIsMentionsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const MAX_DURATION = 60; // Maximum duration in seconds

  const scrollToBottom = () => {
    if (messageContentRef.current) {
      messageContentRef.current.scrollTop = messageContentRef.current.scrollHeight;
    }
  };

  const handleReaction = async (messageId, reaction) => {
    try {
      const messageRef = doc(db, 'rooms', room, 'Messages', messageId);
      const messageDoc = await getDoc(messageRef);
      const currentData = messageDoc.data();

      // Initialize reactions object if it doesn't exist
      const currentReactions = currentData.reactions || {};
      const currentUsers = currentReactions[reaction] || [];

      console.log('Current reactions:', currentReactions); // Debug
      console.log('Current user:', auth.currentUser.uid); // Debug

      // uh Check if user already reacted
      const userIndex = currentUsers.indexOf(auth.currentUser.email);

      if (userIndex > -1) {
        // this should emove user's reaction
        currentUsers.splice(userIndex, 1);
      } else {
        // yh this Adds user's reaction
        currentUsers.push(auth.currentUser.email);
      }

      // Update the reactions in Firestore
      await updateDoc(messageRef, {
        reactions: {
          ...currentReactions,
          [reaction]: currentUsers
        }
      });

    } catch (error) {
      console.error("Error handling reaction:", error);
    }
  };

  useEffect(() => {
    if (!room) return;



    const fetchRoomData = async () => {
      try {
        const roomRef = doc(db, 'rooms', room);
        const roomDoc = await getDoc(roomRef);




        if (roomDoc.exists()) {
          setRoomData(roomDoc.data());
        }
      } catch (error) {
        console.error("Error fetching room data:", error);
      }
    };

    fetchRoomData();
  }, [room]);

  useEffect(() => {

    if (messages.length > 0) {

      setTimeout(() => {
        if (messageContentRef.current) {
          messageContentRef.current.scrollTo({
            top: messageContentRef.current.scrollHeight,
            behavior: "smooth"
          });
        }
      }, 100);
    }
  }, [messages]);


  useEffect(() => {
    if (!room) return;

    const checkRoomCreator = async () => {
      const roomRef = doc(db, 'rooms', room);
      const roomDoc = await getDoc(roomRef);

      if (roomDoc.exists()) {

        setIsRoomCreator(roomDoc.data().createdBy === auth.currentUser?.uid);
      }
    };

    checkRoomCreator();
  }, [room]);


  useEffect(() => {

    if (!room || !auth.currentUser?.uid) return;

    const resetUnreadCount = async () => {
      try {
        const roomRef = doc(db, 'rooms', room);
        await updateDoc(roomRef, {
          [`unreadCounts.${auth.currentUser.uid}`]: 0
        });
      } catch (error) {
        console.error("Failed to reset unread count:", error);
      }
    };

    resetUnreadCount();

  }, [room, userEmail]);


  useEffect(() => {
    if (!room) return;

    setMessages([]);
    setIsLoading(true);

    const messagesRef = collection(db, 'rooms', room, 'Messages');
    const queryMessages = query(messagesRef, orderBy("createdAt"));

    const unsubscribe = onSnapshot(queryMessages, (snapshot) => {

      // 1. THE FIX: Grab all messages from scratch and overwrite the state directly
      const allMessages = snapshot.docs.map(doc => ({
        ...doc.data(),
        id: doc.id
      }));
      setMessages(allMessages); // Look! No more 'prev' gluing!
      setIsLoading(false);

      // 2. Keep all your notification and unread count logic exactly as it was
      snapshot.docChanges().forEach((change) => {
        if (change.type === "added") {
          const messageData = { ...change.doc.data(), id: change.doc.id };

          // Update unread count for other users
          if (messageData.user === auth.currentUser?.email) {
            const roomRef = doc(db, 'rooms', room);
            getDoc(roomRef).then(roomDoc => {
              const roomData = roomDoc.data();
              const participants = [...(roomData.participants || []), roomData.createdBy];
              const unreadCounts = roomData.unreadCounts || {};

              participants.forEach(userId => {
                if (userId !== auth.currentUser.uid) {
                  unreadCounts[userId] = (unreadCounts[userId] || 0) + 1;
                }
              });

              updateDoc(roomRef, { unreadCounts });
            });
          }

          // Show notification for new messages
          const isNewMessage = messageData.createdAt?.seconds >= (Date.now() / 1000 - 2);
          if (isNewMessage &&
            messageData.user !== auth.currentUser?.email &&
            messageData.type !== 'system' &&
            document.hidden) {
            showNotification('New Message', {
              body: `${messageData.user.split('@')[0]}: ${messageData.type === 'voice' ? '­ƒÄñ Voice message' : messageData.text}`,
              tag: `new-message-${change.doc.id}`,
              icon: '/logo192.png'
            });
          }
        }
      });
    });

    return () => unsubscribe();
  }, [room, showNotification]);



  useEffect(() => {
    const unsubscribeAuth = onAuthStateChanged(auth, (user) => {
      if (user) {
        setUserEmail(user.email);
      } else {
        setUserEmail(null);
      }
    });

    return () => unsubscribeAuth();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!room || newMessage === "") return;

    const messageToSend = newMessage;
    const replyToSend = selectedReply;
    setNewMessage("");
    setSelectedReply(null);

    try {
      const messagesRef = collection(db, 'rooms', room, 'Messages');
      const roomRef = doc(db, 'rooms', room);

      // If replying to a message, check its current state
      let replyToData = null;
      if (replyToSend) {
        const replyMessageRef = doc(db, 'rooms', room, 'Messages', replyToSend.id);
        const replyMessageDoc = await getDoc(replyMessageRef);

        if (replyMessageDoc.exists()) {
          const replyMessageData = replyMessageDoc.data();
          replyToData = {
            id: replyToSend.id,
            text: replyMessageData.deleted ? "Message has been deleted" : replyToSend.text,
            user: replyToSend.user,
            type: replyToSend.type,
            deleted: replyMessageData.deleted || false
          };
        }
      }

      await addDoc(messagesRef, {
        text: messageToSend,
        type: 'text',
        createdAt: serverTimestamp(),
        user: auth.currentUser ? auth.currentUser.email : 'Guest',
        room,
        replyTo: replyToData
      });


      await updateDoc(roomRef, {
        lastMessageAt: serverTimestamp(),
        lastMessage: {
          text: messageToSend,
          sender: auth.currentUser.email,
          type: 'text'
        }
      });

    } catch (error) {
      console.error("Error sending message:", error);
      setNewMessage(messageToSend);
      setSelectedReply(replyToSend);
    }
  };

  useEffect(() => {
    if (!room) return;

    const roomRef = doc(db, 'rooms', room);
    const unsubscribe = onSnapshot(roomRef, (snapshot) => {
      const roomData = snapshot.data();
      if (roomData?.pendingRequests?.length > 0 && roomData.createdBy === auth.currentUser?.uid) {
        const requestingUser = roomData.pendingRequests[0];
        setJoinRequest({
          uid: requestingUser.uid,
          email: requestingUser.email
        });
      }
    });

    return () => unsubscribe();
  }, [room]);


  const handleJoinRequest = async (accepted) => {
    if (!joinRequest || !room) return;

    try {
      const roomRef = doc(db, 'rooms', room);
      const roomDoc = await getDoc(roomRef);
      const roomData = roomDoc.data();

      if (accepted) {
        await updateDoc(roomRef, {
          participants: arrayUnion(joinRequest.uid),
          pendingRequests: roomData.pendingRequests.filter(
            req => req.uid !== joinRequest.uid
          )
        });
      } else {
        await updateDoc(roomRef, {
          pendingRequests: roomData.pendingRequests.filter(
            req => req.uid !== joinRequest.uid
          )
        });
      }
      setJoinRequest(null);
    } catch (error) {
      console.error("Error handling join request:", error);
    }
  };

  const handleReply = (message) => {
    if (message.type === 'voice') {
      setSelectedReply({
        id: message.id,
        text: message.type === 'voice' ? '­ƒÄñ Voice message' : message.text,
        user: message.user,
        type: message.type
      });
      messageContentRef.current?.focus();
    } else {
      setSelectedReply({
        id: message.id,
        text: message.text,
        user: message.user,
        type: message.type || 'text'
      });
    };

    // Focus the input immediately
    setTimeout(() => {
      inputRef.current?.focus();
    }, 0);

  };


  const scrollToMessage = (messageId) => {
    const messageElement = document.getElementById(`message-${messageId}`);
    if (messageElement) {
      messageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
      messageElement.classList.add('highlight');
      setTimeout(() => messageElement.classList.remove('highlight'), 2000);
    }
  };


  const handleDeleteMessage = async (message) => {
    try {
      const messageElement = document.getElementById(`message-${message.id}`);
      const currentScroll = messageElement?.parentElement?.scrollTop;

      const messageRef = doc(db, 'rooms', room, 'Messages', message.id);

      if (message.deleted) {
        // If message is already deleted, remove it and all references to it
        const messagesRef = collection(db, 'rooms', room, 'Messages');
        const q = query(messagesRef);
        const querySnapshot = await getDocs(q);

        const batch = writeBatch(db);

        // Delete the original message
        batch.delete(messageRef);

        // Delete all messages that reference this message
        querySnapshot.forEach((doc) => {
          const messageData = doc.data();
          if (messageData.replyTo && messageData.replyTo.id === message.id) {
            batch.delete(doc.ref);
          }
        });

        await batch.commit();
      } else {
        // First deletion - mark as deleted
        await updateDoc(messageRef, {
          deleted: true,
          text: "Message has been deleted",
          reactions: {} // Clear any reactions
        });

        // Update all messages that reference this message
        const messagesRef = collection(db, 'rooms', room, 'Messages');
        const q = query(messagesRef);
        const querySnapshot = await getDocs(q);

        const batch = writeBatch(db);
        querySnapshot.forEach((doc) => {
          const messageData = doc.data();
          if (messageData.replyTo && messageData.replyTo.id === message.id) {
            batch.update(doc.ref, {
              'replyTo.deleted': true,
              'replyTo.text': 'Message has been deleted'
            });
          }
        });
        await batch.commit();
      }

      setSelectedMessageId(null);

      setTimeout(() => {
        if (messageElement?.parentElement && currentScroll) {
          messageElement.parentElement.scrollTop = currentScroll;
        }
      }, 50);
    } catch (error) {
      console.error("Error deleting message:", error);
    }
  };




  const handleMessageClick = (messageId) => {
    setSelectedMessageId(messageId === selectedMessageId ? null : messageId);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      audioChunksRef.current = [];
      setRecordingDuration(0);
      setShowPreview(false);
      setPreviewAudio(null);

      mediaRecorderRef.current.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorderRef.current.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const audioUrl = URL.createObjectURL(audioBlob);
        setPreviewAudio({ blob: audioBlob, url: audioUrl });
        setShowPreview(true);
      };

      // Start duration timer
      timerRef.current = setInterval(() => {
        setRecordingDuration(prev => {
          if (prev >= MAX_DURATION) {
            stopRecording();
            return prev;
          }
          return prev + 1;
        });
      }, 1000);

      mediaRecorderRef.current.start();
      setIsRecording(true);
    } catch (error) {
      console.error("Error starting recording:", error);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      clearInterval(timerRef.current);
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    }
  };

  const cancelRecording = () => {
    setShowPreview(false);
    setPreviewAudio(null);
    setRecordingDuration(0);
  };

  const sendVoiceMessage = async () => {
    if (!previewAudio) return;

    // Store reply state before clearing
    const replyToSend = selectedReply;
    setSelectedReply(null);
    setShowPreview(false);

    const reader = new FileReader();
    reader.readAsDataURL(previewAudio.blob);
    reader.onloadend = async () => {
      const base64Audio = reader.result;

      try {
        const messagesRef = collection(db, 'rooms', room, 'Messages');
        await addDoc(messagesRef, {
          type: 'voice',
          audioData: base64Audio,
          duration: recordingDuration,
          createdAt: serverTimestamp(),
          user: auth.currentUser.email,
          room,
          replyTo: replyToSend ? {
            id: replyToSend.id,
            text: replyToSend.text,
            user: replyToSend.user,
            type: replyToSend.type
          } : null
        });

        // Reset states after successful send
        setPreviewAudio(null);
        setRecordingDuration(0);
      } catch (error) {
        console.error("Error sending voice message:", error);
        // Restore states if sending fails
        setSelectedReply(replyToSend);
        setShowPreview(true);
      }
    };
  };

  const formatDuration = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handlePinMessage = async (messageId) => {
    try {
      const messageRef = doc(db, 'rooms', room, 'Messages', messageId);
      const messageDoc = await getDoc(messageRef);

      if (messageDoc.exists()) {
        const currentPinned = messageDoc.data().pinned || false;
        await updateDoc(messageRef, {
          pinned: !currentPinned,
          pinnedAt: !currentPinned ? serverTimestamp() : null,
          pinnedBy: !currentPinned ? auth.currentUser.email : null
        });
      }
    } catch (error) {
      console.error("Error pinning message:", error);
    }
  };

  const handleSearch = (results) => {
    setSearchResults(results);
  };


  const pinnedCount = messages.filter(msg => msg.pinned).length;
  // A message is a "mention" if someone replied to the current user's message
  const mentions = messages.filter(msg => msg.replyTo && msg.replyTo.user === userEmail);

  return (
    <div className="message-area">
      {room && (
        <>
          <MessageHeader
            roomData={roomData}
            userEmail={userEmail}
            pinnedCount={pinnedCount}
            onPinClick={() => {
              setIsPinnedOpen(!isPinnedOpen);
              setIsMentionsOpen(false);
            }}
            isPinnedOpen={isPinnedOpen}
            mentionsCount={mentions.length}
            onMentionsClick={() => {
              setIsMentionsOpen(!isMentionsOpen);
              setIsPinnedOpen(false);
            }}
            isMentionsOpen={isMentionsOpen}
            messages={messages}
            users={users}
            onSearch={handleSearch}
          />

          {isPinnedOpen && (
            <PinnedMessagesOverlay
              messages={messages}
              onMessageClick={scrollToMessage}
              onUnpin={handlePinMessage}
              onClose={() => setIsPinnedOpen(false)}
            />
          )}

          {isMentionsOpen && (
            <MentionsOverlay
              mentions={mentions}
              onMessageClick={scrollToMessage}
              onClose={() => setIsMentionsOpen(false)}
            />
          )}

          <MessageContent
            messages={searchResults || messages}
            userEmail={userEmail}
            selectedMessageId={selectedMessageId}
            handleMessageClick={handleMessageClick}
            handleReply={handleReply}
            handleDeleteMessage={handleDeleteMessage}
            handlePinMessage={handlePinMessage}
            handleReaction={handleReaction}
            reactions={reactions}
            messageContentRef={messageContentRef}
            scrollToMessage={scrollToMessage}
            auth={auth}
            users={users}
            isLoading={isLoading}
          />

          <MessageInput
            handleSubmit={handleSubmit}
            selectedReply={selectedReply}
            setSelectedReply={setSelectedReply}
            showPreview={showPreview}
            previewAudio={previewAudio}
            cancelRecording={cancelRecording}
            sendVoiceMessage={sendVoiceMessage}
            inputRef={inputRef}
            newMessage={newMessage}
            setNewMessage={setNewMessage}
            isRecording={isRecording}
            startRecording={startRecording}
            stopRecording={stopRecording}
            recordingDuration={recordingDuration}
            formatDuration={formatDuration}
          />

          {isRoomCreator && joinRequest && (
            <ChatRequestPopup
              requestingUser={joinRequest}
              onAccept={() => handleJoinRequest(true)}
              onDecline={() => handleJoinRequest(false)}
            />
          )}
        </>
      )}
    </div>

